(()=>{window.scrollTo(0,0);var nav=document.querySelector(".nav"),scrolled=!1,darkSections=(nav&&window.addEventListener("scroll",function(){var shouldBeScrolled=50<window.pageYOffset;shouldBeScrolled!==scrolled&&((scrolled=shouldBeScrolled)?nav.classList.add("nav--scrolled"):nav.classList.remove("nav--scrolled"))}),document.querySelectorAll(".section--dark")),revealEls=(nav&&darkSections.length&&window.addEventListener("scroll",function(){for(var navBottom=nav.getBoundingClientRect().bottom+32,overDark=!1,i=0;i<darkSections.length;i++){var rect=darkSections[i].getBoundingClientRect();if(rect.top<navBottom&&0<rect.bottom){overDark=!0;break}}overDark?nav.classList.add("nav--over-dark"):nav.classList.remove("nav--over-dark")}),document.querySelectorAll("[reveal]"));if("IntersectionObserver"in window)for(var observer=new IntersectionObserver(function(entries){for(var i=0;i<entries.length;i++)entries[i].isIntersecting&&(entries[i].target.classList.add("reveal--visible"),observer.unobserve(entries[i].target))},{threshold:.12}),i=0;i<revealEls.length;i++)observer.observe(revealEls[i]);else for(var j=0;j<revealEls.length;j++)revealEls[j].classList.add("reveal--visible");for(var smoothLinks=document.querySelectorAll("[smooth-scroll]"),k=0;k<smoothLinks.length;k++)smoothLinks[k].addEventListener("click",function(e){e.preventDefault();e=this.getAttribute("href").replace("#",""),e=document.getElementById(e);e&&e.scrollIntoView({behavior:"smooth",block:"start"})})})();